namespace sv_9ea8d6315751451eb8222bb7ae380d5f.Services;

/// <summary>
/// Scoped service that tracks low-stock alert counts for a warehouse.
/// Polling is controlled by the consuming component (start/stop),
/// and all subscribers are notified via <see cref="OnChange"/> when
/// new data arrives — regardless of which component triggered the poll.
/// </summary>
public class InventoryAlertService : IDisposable
{
    private readonly Random _random = new();
    private CancellationTokenSource? _cts;

    public int LowStockCount { get; private set; }
    public string CurrentWarehouseId { get; private set; } = string.Empty;

    public event Action? OnChange;

    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulates a database query — returns a random count of items
        // below minimum stock levels for the given warehouse.
        return Task.FromResult(_random.Next(0, 16));
    }

    public void StartPolling(string warehouseId)
    {
        StopPolling();
        CurrentWarehouseId = warehouseId;
        _cts = new CancellationTokenSource();
        _ = PollLoopAsync(_cts.Token);
    }

    public void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));

        // Fetch immediately on start, then every 10 seconds.
        do
        {
            if (ct.IsCancellationRequested) break;

            LowStockCount = await GetLowStockCountAsync(CurrentWarehouseId);
            OnChange?.Invoke();
        }
        while (await WaitNextAsync(timer, ct));
    }

    private static async Task<bool> WaitNextAsync(PeriodicTimer timer, CancellationToken ct)
    {
        try { return await timer.WaitForNextTickAsync(ct); }
        catch (OperationCanceledException) { return false; }
    }

    public void Dispose()
    {
        StopPolling();
        GC.SuppressFinalize(this);
    }
}

