@* Interactive dropdown rendered inside the static MainLayout.
   Uses CascadingValueSource<WarehouseInfo> to push the selection
   across render-mode boundaries to all interactive components. *@

@rendermode InteractiveServer
@using sv_9ea8d6315751451eb8222bb7ae380d5f.Services
@inject CascadingValueSource<WarehouseInfo> WarehouseSource
@implements IDisposable

<select class="form-select form-select-sm"
        value="@_selectedId"
        @onchange="OnWarehouseChanged"
        style="max-width: 200px;">
    @foreach (var wh in WarehouseInfo.All)
    {
        <option value="@wh.WarehouseId">@wh.WarehouseName</option>
    }
</select>

@code {
    private string _selectedId = WarehouseInfo.All[0].WarehouseId;

    [CascadingParameter]
    private WarehouseInfo? Warehouse { get; set; }

    protected override void OnParametersSet()
    {
        if (Warehouse is not null)
        {
            _selectedId = Warehouse.WarehouseId;
        }
    }

    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        _selectedId = e.Value?.ToString() ?? WarehouseInfo.All[0].WarehouseId;
        var selected = WarehouseInfo.All.First(w => w.WarehouseId == _selectedId);
        await WarehouseSource.NotifyChangedAsync(
            new WarehouseInfo
            {
                WarehouseId = selected.WarehouseId,
                WarehouseName = selected.WarehouseName
            });
    }

    public void Dispose() { }
}

@* Interactive badge that subscribes to InventoryAlertService.OnChange.
   Updates automatically whenever ANY component triggers a new poll result. *@

@rendermode InteractiveServer
@using sv_9ea8d6315751451eb8222bb7ae380d5f.Services
@inject InventoryAlertService AlertService
@implements IDisposable

@if (AlertService.LowStockCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-2">@AlertService.LowStockCount</span>
}
else
{
    <span class="badge bg-success rounded-pill ms-2">0</span>
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        // Wrap in InvokeAsync because the event fires from a background timer thread.
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnChange += _handler;
    }

    public void Dispose()
    {
        AlertService.OnChange -= _handler;
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@using sv_9ea8d6315751451eb8222bb7ae380d5f.Services
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<p>
    Currently viewing: <strong>@(Warehouse?.WarehouseName ?? "Unknown")</strong>
</p>

<div class="card" style="max-width: 320px;">
    <div class="card-body">
        <h5 class="card-title">Low-Stock Alerts</h5>
        <p class="card-text display-4">
            @AlertService.LowStockCount
        </p>
        <p class="text-muted">items below minimum level (refreshes every 10 s)</p>
    </div>
</div>

@code {
    [CascadingParameter]
    private WarehouseInfo? Warehouse { get; set; }

    private Action? _handler;
    private string _activeWarehouseId = string.Empty;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnChange += _handler;
    }

    protected override void OnParametersSet()
    {
        var warehouseId = Warehouse?.WarehouseId ?? WarehouseInfo.All[0].WarehouseId;

        // (Re)start polling whenever the selected warehouse changes.
        if (warehouseId != _activeWarehouseId)
        {
            _activeWarehouseId = warehouseId;
            AlertService.StartPolling(_activeWarehouseId);
        }
    }

    public void Dispose()
    {
        AlertService.OnChange -= _handler;
        AlertService.StopPolling();
    }
}

