@* Interactive badge that subscribes to InventoryAlertService.OnChange.
   Updates automatically whenever ANY component triggers a new poll result. *@

@rendermode InteractiveServer
@using sv_9ea8d6315751451eb8222bb7ae380d5f.Services
@inject InventoryAlertService AlertService
@implements IDisposable

@if (AlertService.LowStockCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-2">@AlertService.LowStockCount</span>
}
else
{
    <span class="badge bg-success rounded-pill ms-2">0</span>
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        // Wrap in InvokeAsync because the event fires from a background timer thread.
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnChange += _handler;
    }

    public void Dispose()
    {
        AlertService.OnChange -= _handler;
    }
}

